import re

from .generic import apply_rules

DEFAULT_RULES = {
    # -minen nouns, ΟΛ/ΟΕ/y + a/o/u
    # https://en.wiktionary.org/wiki/-minen
    # too much noise: "mista", "mistΟΛ"
    re.compile(r"(miset|misen|misten|miseen|misia|misiΟΛ|misiin|misin)$"): "minen",
    # -inen nouns
    # too much noise: "isten"
    re.compile(
        r"(?:isissa|isissΟΛ|isista|isistΟΛ|iseksi|iseen|isella|isellΟΛ|iselle|iselta|iseltΟΛ|iseni|isensa|isensΟΛ|isesi|isessa|isessΟΛ|isesta|isestΟΛ|isien|isiksi|isilla|isillΟΛ|isilta|isiltΟΛ|isina|isinΟΛ|isineen|isitta|isittΟΛ|isemme|isenne|isille|isetta|isettΟΛ)$"
    ): "inen",
    # -ainen for more precision
    # liikenaisen βÜ£ liikenainen
    # liikenaiset βÜ£ liikenainen
    # liikenaisia βÜ£ liikenainen
    # too much noise: "aisin", "aista"
    re.compile(r"(?:aisen|aiset|aisia)$"): "ainen",
    # -uus nouns: https://en.wiktionary.org/wiki/nerokkuus
    # too much noise: "uutta"
    re.compile(
        r"(?:uudet|uuden|uuksien|uuksiin|uuksia|uudessa|uuksissa|uuteen|uudella|uuksilla|uudelta|uuksilta|uudelle|uuksille|uutena|uuksina|uudeksi|uuksiksi|uuksin|uudetta|uuksitta|uuksineen|uuteni|uutemme|uutesi|uutenne|uutensa)$"
    ): "uus",
    # -tti: https://en.wiktionary.org/wiki/luotti
    # too much noise: "ttiin", "teille", "teiksi", "teista", "teilla", "teilta", "teillΟΛ", "teiltΟΛ", "teitta", "teittΟΛ", "teissa", "teissΟΛ", "tille", "tiksi", "tissa", "titta", "tilta", "teistΟΛ", "tteineen", "tteihin", "tteina"
    re.compile(
        r"(?:ttien|ttia|ttiΟΛ|tteja|ttejΟΛ|tissΟΛ|tiltΟΛ|ttina|ttinΟΛ|tteinΟΛ|tittΟΛ|ttini|ttimme|ttisi|ttinne|ttinsa|ttinsΟΛ)$"
    ): "tti",
}


def apply_fi(token: str) -> str | None:
    "Apply pre-defined rules for Finnish."
    if len(token) < 10 or token[0].isupper():
        return None

    ## others: but not yritteineen/yrite
    # if token.endswith("eineen") and token[-7] != token[-8]:
    #    return token[:-6] + "i"
    ## too rare?
    # ΟΛyskΟΛisen βÜ£ ΟΛyskΟΛistΟΛ
    # if token.endswith("ΟΛisen"):
    #    return token[:-4]

    return apply_rules(token, DEFAULT_RULES)
